const page = $input.first().json;
const props = page.properties || {};
return [{ json: {
  production_order_id: props['Order ID']?.rich_text?.[0]?.plain_text || `ANI-${Date.now()}`,
  client: props['Client']?.select?.name || 'Unknown',
  project_name: props['Project']?.title?.[0]?.plain_text || 'Anime Project',
  characters: [],
  scenes: [],
  style: props['Style']?.select?.name || 'anime_cel_shaded',
  notion_page_id: page.id,
}}];

// GPU availability check — determines free (local) vs paid (API) path
const order = $json;
// STUB: Check if ComfyUI Desktop is running on localhost:8188
const gpuAvailable = false; // Set to true when ComfyUI Desktop is running
return [{ json: { ...order, gpu_available: gpuAvailable, generation_path: gpuAvailable ? 'local_comfyui' : 'fal_api' }}];

// ComfyUI: Generate character sheets (10-12 poses per character)
// Uses SDXL + anime LoRA for style consistency
const order = $json;
return [{ json: { ...order, character_sheets_status: 'stub', character_count: order.characters.length || 1 }}];
// STUB: ComfyUI character sheet generation pipeline

// LoRA training check — train if new character, skip if existing
const order = $json;
return [{ json: { ...order, lora_status: 'stub_skipped', lora_note: 'LoRA training async — triggered separately if new character' }}];
// STUB: ComfyUI Expert lora-training sub-skill

// Per-scene generation: AnimateDiff V3 + motion LoRAs or Wan 2.6
// If GPU available: local ComfyUI (free)
// If no GPU: fal.ai Wan 2.6 cloud ($0.10/sec)
const scene = $json;
const isLocal = scene.generation_path === 'local_comfyui';
return [{ json: { ...scene, generation_engine: isLocal ? 'comfyui_animatediff' : 'fal_wan26', generation_cost: isLocal ? 0 : (scene.duration_seconds || 5) * 0.10 }}];
// STUB: Routes to ComfyUI local or fal.ai cloud

// Style transfer + ComfyUI post-processing
// Apply anime LoRA style, deflicker, face enhance
const scene = $json;
return [{ json: { ...scene, style_transfer_status: 'stub', style_applied: scene.style || 'anime_cel_shaded' }}];
// STUB: ComfyUI style transfer LoRA application

const allScenes = $input.all().map(i => i.json);
const totalCost = allScenes.reduce((s, sc) => s + (sc.generation_cost || 0), 0);
return [{ json: { scenes: allScenes, total_generation_cost: totalCost, scene_count: allScenes.length }}];

// ElevenLabs: Japanese voice cast + ambient SFX
const order = $json;
return [{ json: { ...order, voice_cast_status: 'stub', sfx_status: 'stub', audio_cost: 0.10 }}];
// STUB: ElevenLabs voice generation for anime characters

// ComfyUI lip-sync: LatentSync 1.6 for dialogue scenes
const order = $json;
return [{ json: { ...order, lipsync_status: 'stub', lipsync_method: 'latentsync_1.6' }}];
// STUB: ComfyUI local LatentSync or Muapi cloud LatentSync

// Remotion: Anime composition — opening titles, subtitles, credits
// Uses high-saturation LUT, anime-specific transitions
const order = $json;
return [{ json: { ...order, remotion_template: 'Generic', remotion_note: 'Generic template with anime config: high saturation, bold transitions, opening titles, subtitle track, credits roll' }}];
// STUB: Remotion CLI with anime-configured Generic template

// FFmpeg: encode to broadcast spec
const order = $json;
const total = (order.total_generation_cost || 0) + (order.audio_cost || 0);
return [{ json: { production_order_id: order.production_order_id, total_cost: total, encode_spec: 'broadcast_1080p_h264', status: 'QC Review' }}];
